using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateInMemoryContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06")
            };

            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var student1 = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            var student2 = new Student
            {
                ID = 11,
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };
            var student3 = new Student
            {
                ID = 12,
                FirstMidName = "Arturo",
                LastName = "Anand",
                EnrollmentDate = DateTime.Parse("2013-09-01")
            };

            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            var enrollment1 = new Enrollment
            {
                EnrollmentID = 1,
                StudentID = 10,
                CourseID = 1050,
                Grade = Grade.A
            };
            var enrollment2 = new Enrollment
            {
                EnrollmentID = 2,
                StudentID = 11,
                CourseID = 4022,
                Grade = Grade.B
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);
            context.SaveChanges();

            var officeAssignment = new OfficeAssignment
            {
                InstructorID = 2,
                Location = "Smith 17"
            };
            context.OfficeAssignments.Add(officeAssignment);
            context.SaveChanges();

            var courseAssignment1 = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };
            var courseAssignment2 = new CourseAssignment
            {
                InstructorID = 2,
                CourseID = 4022
            };

            context.CourseAssignments.AddRange(courseAssignment1, courseAssignment2);
            context.SaveChanges();
        }
    }
}

