using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void EnrollmentDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };

            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Enrollments_CanBeInitializedAsCollection()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { EnrollmentID = 1 },
                    new Enrollment { EnrollmentID = 2 }
                }
            };

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_ValidationAttributes_RequiresLastName()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            var context = new ValidationContext(student);
            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                student.LastName,
                new ValidationContext(student) { MemberName = nameof(Student.LastName) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Student_ValidationAttributes_RequiresFirstMidName()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = DateTime.Today
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                student.FirstMidName,
                new ValidationContext(student) { MemberName = nameof(Student.FirstMidName) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Student_LastName_MaxLength50()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                student.LastName,
                new ValidationContext(student) { MemberName = nameof(Student.LastName) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Student_ValidModel_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateObject(student, new ValidationContext(student), results, true);

            Assert.True(isValid);
        }
    }
}

using System.Collections.Generic;
