                course.Credits,
                new ValidationContext(course) { MemberName = nameof(Course.Credits) },
                results);

            Assert.False(isValid);
        }

        [Theory]
        [InlineData(0)]
        [InlineData(3)]
        [InlineData(5)]
        public void Course_Credits_ValidRange_PassesValidation(int credits)
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test Course",
                Credits = credits,
                DepartmentID = 1
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = nameof(Course.Credits) },
                results);

            Assert.True(isValid);
        }

        [Fact]
        public void Course_Title_TooShort()
        {
