using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
    {
        [Fact]
        public void Course_Properties_CanBeSet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_CanBeNull()
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = 3, DepartmentID = 1 };

            Assert.Null(course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_CanBeSet()
        {
            var course = new Course { TeachingMaterialImagePath = "/Uploads/test.jpg" };

            Assert.Equal("/Uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_Credits_RangeValidation_TooHigh()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test Course",
                Credits = 6,
                DepartmentID = 1
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = nameof(Course.Credits) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Course_Credits_RangeValidation_Negative()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test Course",
                Credits = -1,
                DepartmentID = 1
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = nameof(Course.Credits) },
                results);

            Assert.False(isValid);
        }

        [Theory]
        [InlineData(0)]
        [InlineData(3)]
        [InlineData(5)]
        public void Course_Credits_ValidRange_PassesValidation(int credits)
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test Course",
                Credits = credits,
                DepartmentID = 1
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = nameof(Course.Credits) },
                results);

            Assert.True(isValid);
        }

        [Fact]
        public void Course_Title_TooShort()
        {
            var course = new Course { CourseID = 1, Title = "AB", Credits = 3, DepartmentID = 1 };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Title,
                new ValidationContext(course) { MemberName = nameof(Course.Title) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Course_Title_TooLong()
        {
            var course = new Course { CourseID = 1, Title = new string('A', 51), Credits = 3, DepartmentID = 1 };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                course.Title,
                new ValidationContext(course) { MemberName = nameof(Course.Title) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Course_NavigationProperties_CanBeSet()
        {
            var dept = new Department { DepartmentID = 1, Name = "English" };
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 3,
                Department = dept,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.Same(dept, course.Department);
            Assert.Empty(course.Enrollments);
            Assert.Empty(course.CourseAssignments);
        }
    }
}

