using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Properties_CanBeSet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 10,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(10, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 10
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_NavigationProperties_CanBeSet()
        {
            var course = new Course { CourseID = 1050, Title = "Chem", Credits = 3 };
            var student = new Student { ID = 10, LastName = "Smith", FirstMidName = "John" };
            var enrollment = new Enrollment
            {
                Course = course,
                Student = student
            };

            Assert.Same(course, enrollment.Course);
            Assert.Same(student, enrollment.Student);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }
}

