using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void HireDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor { HireDate = date };

            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void CourseAssignments_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1 },
                    new CourseAssignment { CourseID = 2 }
                }
            };

            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void OfficeAssignment_CanBeSet()
        {
            var office = new OfficeAssignment { Location = "Room 101" };
            var instructor = new Instructor { OfficeAssignment = office };

            Assert.Same(office, instructor.OfficeAssignment);
        }

        [Fact]
        public void OfficeAssignment_CanBeNull()
        {
            var instructor = new Instructor();

            Assert.Null(instructor.OfficeAssignment);
        }

        [Fact]
        public void Instructor_ValidModel_PassesValidation()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = new DateTime(2020, 1, 1)
            };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateObject(instructor, new ValidationContext(instructor), results, true);

            Assert.True(isValid);
        }
    }
}

