using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        [Fact]
        public void Department_Properties_CanBeSet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(new DateTime(2007, 9, 1), dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test", DepartmentID = 1 };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_CanBeSet()
        {
            var version = new byte[] { 1, 2, 3, 4 };
            var dept = new Department { RowVersion = version };
            Assert.Equal(version, dept.RowVersion);
        }

        [Fact]
        public void Department_NavigationProperties()
        {
            var instructor = new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John" };
            var dept = new Department
            {
                Name = "Test",
                Administrator = instructor,
                Courses = new List<Course>()
            };

            Assert.Same(instructor, dept.Administrator);
            Assert.Empty(dept.Courses);
        }

        [Fact]
        public void Department_Name_TooShort_FailsValidation()
        {
            var dept = new Department { DepartmentID = 1, Name = "AB", Budget = 100 };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                dept.Name,
                new ValidationContext(dept) { MemberName = nameof(Department.Name) },
                results);

            Assert.False(isValid);
        }

        [Fact]
        public void Department_Name_TooLong_FailsValidation()
        {
            var dept = new Department { DepartmentID = 1, Name = new string('A', 51), Budget = 100 };

            var results = new List<ValidationResult>();
            var isValid = Validator.TryValidateProperty(
                dept.Name,
                new ValidationContext(dept) { MemberName = nameof(Department.Name) },
                results);

            Assert.False(isValid);
        }
    }
