using System;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Notification_Properties_CanBeSet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student has been created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student has been created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAt_CanBeSet()
        {
            var readTime = DateTime.Now;
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readTime
            };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_AllValues_Exist(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }

        [Fact]
        public void EntityOperation_ToString_ReturnsExpectedValues()
        {
            Assert.Equal("CREATE", EntityOperation.CREATE.ToString());
            Assert.Equal("UPDATE", EntityOperation.UPDATE.ToString());
            Assert.Equal("DELETE", EntityOperation.DELETE.ToString());
        }
    }
}

