            var ca = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 7777
            };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments
                .First(x => x.CourseID == 7777 && x.InstructorID == instructor.ID);
            Assert.NotNull(retrieved);
        }
    }
