using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewResult_WithInstructorSelect()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000m,
                StartDate = new DateTime(2023, 1, 1),
                InstructorID = 1
            };

            var result = _controller.Create(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidModel_AddsToDatabase()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000m,
                StartDate = new DateTime(2023, 1, 1),
                InstructorID = 1
            };

            _controller.Create(department);

            Assert.Contains(_context.Departments, d => d.Name == "Physics");
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = _controller.Create(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_GET_ReturnsViewResult_WithDepartment()
        {
            var result = _controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
