using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var result = _controller.Index(1, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_ShowsEnrollments()
        {
            var result = _controller.Index(1, 1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewResult_WithCoursesInViewBag()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidModel_AddsToDatabase()
        {
            var instructor = new Instructor
            {
                LastName = "DatabaseTest",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);

            Assert.Contains(_context.Instructors, i => i.LastName == "DatabaseTest");
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_CreatesAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var selectedCourses = new[] { "1050", "4022" };
            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors.First(i => i.LastName == "WithCourses");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor();

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsViewResult()
        {
            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
        {
            var countBefore = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Department 1 has InstructorID = 1
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept!.InstructorID);
        }
    }
}

