namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();
            // Drain queue
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue
            while (_notificationService.ReceiveNotification() != null) { }
            _notificationService.Dispose();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
        {
            // Drain any leftover notifications
            while (_notificationService.ReceiveNotification() != null) { }

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
        {
            _notificationService.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
            _notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE, "Admin");

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }
    }
}

