using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Today
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 1000,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(9999);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved!.Title);
        }

        [Fact]
        public void CanAddAndRetrieveEnrollment()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = DateTime.Today
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var dept = new Department
            {
                Name = "Eng",
                Budget = 1000,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 8888,
                Title = "Enroll Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = 8888,
                Grade = Grade.A
            };

            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.CourseID == 8888);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CanAddAndRetrieveNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Key",
                LastName = "Test",
                HireDate = DateTime.Today
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var dept = new Department
            {
                Name = "Key Dept",
                Budget = 1000,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 7777,
                Title = "Key Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 7777
            };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments
                .First(x => x.CourseID == 7777 && x.InstructorID == instructor.ID);
            Assert.NotNull(retrieved);
        }
    }
}

