using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_DoesNotDuplicateData_WhenCalledTwice()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            Assert.Equal(7, context.Courses.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesStudentsWithCorrectNames()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Contains(context.Students, s => s.LastName == "Alexander" && s.FirstMidName == "Carson");
            Assert.Contains(context.Students, s => s.LastName == "Alonso" && s.FirstMidName == "Meredith");
            Assert.Contains(context.Students, s => s.LastName == "Olivetto" && s.FirstMidName == "Nino");
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesCoursesWithCorrectData()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var chemistry = context.Courses.Find(1050);
            Assert.NotNull(chemistry);
            Assert.Equal("Chemistry", chemistry!.Title);
            Assert.Equal(3, chemistry.Credits);
            context.Dispose();
        }
    }
}

